_NL = 3

def _fwd(x):
    # standardize
    z = [(x[i] - MEAN[i]) / STD[i] for i in range(len(x))]
    for li in range(_NL):
        W = globals()['W%d' % li]; B = globals()['B%d' % li]
        out = []
        for r in range(len(W)):
            row = W[r]
            acc = B[r]
            for c in range(len(row)):
                acc += row[c] * z[c]
            out.append(acc)
        if li < _NL - 1:
            out = [v if v > 0.0 else 0.0 for v in out]  # ReLU
        z = out
    return z[0]


def score_many(rows):
    return [_fwd([float(v) for v in r]) for r in rows]
